import numpy as np
import matplotlib.pyplot as plt

# 1. Load the CSV generated by Nyquist
matrix_data = np.genfromtxt('matrix.csv', delimiter=',', usecols=np.arange(256))

# 2. Setup the plot
plt.figure(figsize=(10, 8))
# 'magma' or 'viridis' are great color maps for this type of data
im = plt.imshow(matrix_data, cmap='magma', interpolation='nearest') 

# 3. Add labels and aesthetics
plt.colorbar(im, label='Pitch Distance (Semitones)')
plt.title('Self-Similarity Matrix: Gaussian Markov Composer')
plt.xlabel('Note Index (Time)')
plt.ylabel('Note Index (Time)')

# 4. Render
plt.tight_layout()
plt.show()